(4, ' EPSON ปริ้นเตอร์อิงค์เจ็ท รุ่น L1256', 'ประเภทของเครื่อง:Print Tank System (Wi-Fi)\nความละเอียดหัวพิมพ์:5760 x 1440 dpi\nความเร็วในการพิมพ์ขาว-ดำ(นาที):33 แผ่น/นาที\nความเร็วในการพิมพ์สี(นาที):15 แผ่น/นาที\nตลับหมึก:INK003 ปริมาณการพิมพ์ BK 7500 Color 4500\nการเชื่อมต่อ:USB 2.0 Wi-Fi & Wi-Fi Direct\nขนาด(ซม.):37.50 W x 16.90 H x 34.70 D\nขนาดกระดาษที่รองรับ:A4, B5, A5, B6, A6\nน้ำหนัก(กิโลกรัม):3.9', 3990.00, 'electronics', 'ใหม่ 100%', 'data:image/jpeg;base64,', 5, 'active', '2026-02-24 20:19:49');
INSERT INTO `products` (`id`, `name`, `description`, `price`, `category`, `condition_text`, `image`, `seller_id`, `status`, `created_at`) VALUES
(5, 'D-LINK เราเตอร์ไร้สาย รุ่น DIR-809 AC750 DUAL BAND', 'เราเตอร์ไร้สาย รุ่น DIR-809 AC750 DUAL BAND\n\nรองรับการทำงานได้หลายโหมด\nDIR-809 รองรับการทำงานได้หลายโหมด (โหมดเร้าท์เตอร์ โหมด Access point โหมดการใช้เป็นรีพีเตอร์) เพิ่มความสะดวกสบายให้การจัดการด้านเน็ตเวิร์ค\nเป็นมากกว่าด้วยเทคโนโลยี ดูอัล-แบนด์\nใช้ช่องความถี่ 2.4GHz เพื่อการใช้งานในทุกๆ ด้าน ในขณะที่ใช้ความถี่ 5GHz AC เพื่อการใช้งานด้าน HD วีดีโอ สตรีมมิ่ง การเล่นเกมออนไลน์และการส่งไฟล์ขนาดใหญ่ ด้วยดีไวซ์ที่มีการใช้ย่านความถี่ความเร็วสูงที่ 5GHz ช่วยให้คุณใช้งานได้ประสิทธิภาพที่ดียิ่งขึ้น และเพิ่มความสะดวกสบายต่อการใช้งานไวร์เลส\n3 เสาสัญญาณไวไฟ เพิ่มประสิทธิภาพสัญญาณได้ครอบคลุมมากขึ้น\nด้วยไวร์เลส N300 คลาวด์เร้าท์เตอร์ เพิ่มสัญญาณครอบคลุมได้มากยิ่งขึ้น ซึ่งมาพร้อมเสาสัญญาณ 3 เสา ทำให้สัญญาณได้ครอบคลุม ทำให้คุณสามารถใช้งานได้เร็วมากขึ้น และกว้างขึ้น เพิ่มความเสถียรมากยิ่งขึ้น ทำให้คุณสามารถทำวีดีโอ HD สตรีมมิ่ง การทำวีดีโอแชท การเล่นเกมออนไลน์ โดยไม่มีสัญญาณสะดุดหรือข้อจำกัดอีกต่อไป\nประเภท:WIRELESS ROUTERS D-LINK\nสี:BLACK\nรุ่น:DIR-809\nความเร็ว:AC750 MBPS\nฟังก์ชั่น:EASY TO SET UP,EASY TO\nSECURE\nการเชื่อมต่อ:WIRELESS,LAN\nรับประกัน:LIFETIME', 774.00, 'electronics', 'ใหม่ 100%', 'data:image/webp;base64,', 5, 'active', '2026-02-24 20:22:25');
INSERT INTO `products` (`id`, `name`, `description`, `price`, `category`, `condition_text`, `image`, `seller_id`, `status`, `created_at`) VALUES
(6, 'เสื้อยืดแขนสั้น TEE', 'เสื้อยืดแขนสั้น TEE\nเสื้อยืดคอกลมทรงมาตรฐาน ใส่สบาย ระบายอากาศดี เหมาะสำหรับการสวมใส่ในทุกวัน เนื้อสัมผัสนุ่ม สวมใส่คล่องตัว เคลื่อนไหวง่าย ดีไซน์เรียบสะอาดตา แมทช์ได้กับหลากหลายสไตล์ คงรูปดีหลังซัก\n\nคุณสมบัติ\nคอกลมมาตรฐาน ขอบคอช่วยคงรูป\nสัมผัสนุ่ม ไม่ระคายผิว\nดูแลรักษาง่าย เหมาะกับการใช้งานทุกวัน\nเหมาะสำหรับ\nการสวมใส่ลำลอง ทำงานแบบแคชวล หรือเดินทาง\nแมทช์กับกางเกงยีนส์ ขาสั้น หรือจ็อกเกอร์ได้หลากหลายลุค\nผู้ที่ชอบเสื้อยืดเรียบง่าย ใส่ง่าย และดูดี\nการดูแลรักษา\nซักน้ำอุณหภูมิปกติด้วยผงซักฟอกอ่อน\nหลีกเลี่ยงน้ำยาฟอกขาวและการอบด้วยความร้อนสูง\nตากในที่ร่ม อากาศถ่ายเท เพื่อคงสีและรูปทรง\nรีดด้วยไฟอ่อนจากด้านในของผ้าเมื่อจำเป็น', 490.00, 'fashion', 'ใหม่ 100%', 'data:image/webp;base64,', 5, 'active', '2026-02-24 20:25:21');
INSERT INTO `products` (`id`, `name`, `description`, `price`, `category`, `condition_text`, `image`, `seller_id`, `status`, `created_at`) VALUES
